    /// Enqueue work. Returns false if the processor is stopped or the queue is full.
    /// </summary>
    public ValueTask<bool> EnqueueAsync(WorkItem item, CancellationToken ct = default)
        => _queue.Writer.WaitToWriteAsync(ct).IsCompletedSuccessfully
            ? new ValueTask<bool>(_queue.Writer.TryWrite(item))
            : SlowEnqueueAsync(item, ct);

    private async ValueTask<bool> SlowEnqueueAsync(WorkItem item, CancellationToken ct)
    {
        if (await _queue.Writer.WaitToWriteAsync(ct))
            return _queue.Writer.TryWrite(item);
        return false;
    }

    private async Task ProcessLoopAsync(CancellationToken ct)
    {
        // ReadAllAsync respects the token — when cancelled it stops iterating
        // immediately. No Thread.Abort() needed.
        await foreach (var item in _queue.Reader.ReadAllAsync(ct))
