            catch (OperationCanceledException) when (ct.IsCancellationRequested)
            {
                // Graceful shutdown requested — roll back in-flight work
                // exactly like the old ThreadAbortException handler.
                RollbackCurrentTransaction();
                break;
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    public async Task StopAsync(TimeSpan? timeout = null)
    {
        timeout ??= TimeSpan.FromSeconds(5);

        // Signal the channel as complete so no new items are accepted.
        _queue.Writer.TryComplete();

        // Wait for the worker to drain remaining items, or cancel after timeout.
        if (_workerTask is not null)
        {
            using var timeoutCts = new CancellationTokenSource(timeout.Value);
            try
            {
                await _workerTask.WaitAsync(timeoutCts.Token);
            }
            catch (TimeoutException)
            {
                // Worker didn't finish in time — cancel it cooperatively.
                // This is the .NET 8 equivalent of Thread.Abort().
                await _cts.CancelAsync();

                // Give it a moment to handle OperationCanceledException.
                try { await _workerTask.WaitAsync(TimeSpan.FromSeconds(2)); }
                catch (OperationCanceledException) { /* expected */ }
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        await StopAsync();
        _cts.Dispose();
    }

